%[text] **Problem 1.2: System in DT State Space**
LTI_sys_d = c2d(LTI_sys,Ts) %Discrete System %[output:8b733507]
Ad = LTI_sys_d.A %[output:7ba717ab]
Bd = LTI_sys_d.B %[output:2d838297]
