%[text] **Problem 1.5: P-LQN Formulation & solution with quadprog.m**
%[text] 
%[text] There is no terminal constraint, and there is no state cost, so the optimal control input is **zero**. The controller has no requirement to balance the pendulum, and zero input over the time horizon minimizes the cost function.
%[text] 
%[text] ![](text:image:40d7)
%%
% % ChatGPT was used for this section of the script

% --- parameters (edit if needed) ---
Ts = 0.25;
N  = 20;           % horizon
nx = 2;            % state dimension
nu = 1;            % input dimension

% discrete system (your values)
A = [1 Ts; 0 1];
B = [0.5*Ts^2; Ts];

% initial condition x0 (example: pi/2, 0)
x0 = [pi/2; 0];

% --- decision variable sizes ---
nXvars = nx * N;         % x1..xN
nUvars = nu * N;         % u0..u_{N-1}
nVars  = nXvars + nUvars;

% --- cost: J = sum_{k=0}^{N-1} u_k^2 ---
H = zeros(nVars);
% put identity on the u-block:
u_idx = nXvars + (1:nUvars);      % column indices for u in z
H(u_idx,u_idx) = eye(nUvars);     % weight = 1 on each u_k
f = zeros(nVars,1);

% --- equality constraints: enforce dynamics x_{k+1} - A x_k - B u_k = 0 ---
Aeq = zeros(nx*N, nVars);
beq = zeros(nx*N, 1);

for k = 0:(N-1)
    row_idx = k*nx + (1:nx);         % rows for this dynamic equation (for x_{k+1})
    % column indices for x_{k+1} variable:
    col_xkp1 = (k)*nx + (1:nx);      % because x1 starts at index 1 when k=0

    % place +I on x_{k+1}
    Aeq(row_idx, col_xkp1) = eye(nx);

    % place -A on x_k (except when k==0; x0 is known)
    if k >= 1
        col_xk = (k-1)*nx + (1:nx);  % x_k variable column indices
        Aeq(row_idx, col_xk) = -A;
    end

    % place -B on u_k column
    col_uk = nXvars + k*nu + (1:nu);   % u_k column indices
    Aeq(row_idx, col_uk) = -B;

    % RHS: for k==0 move A*x0 to beq
    if k == 0
        beq(row_idx) = A * x0;
    else
        beq(row_idx) = zeros(nx,1);
    end
end

% no inequalities or bounds in this example
Aineq = [];
bineq = [];
lb = [];
ub = [];

% --- solve QP ---
opts = optimoptions('quadprog','Display','off');
z_opt = quadprog(H,f,Aineq,bineq,Aeq,beq,lb,ub,[],opts);

% --- parse result ---
X_opt = reshape(z_opt(1:nXvars), nx, N);    % columns are x1..xN
U_opt = z_opt(nXvars+1:end);                % u0..u_{N-1}

% include x0 to plot full state trajectory
X_full = [x0, X_opt];   % columns x0..xN

% quick plot (theta vs theta_dot phase plane)
figure; %[output:07eb253e]
plot(X_full(1,:), X_full(2,:), '-o'); %[output:07eb253e]
xlabel('\theta'); ylabel('\theta_dot'); %[output:07eb253e]
title('Phase plane (enforcing dynamics, no terminal equality)'); %[output:07eb253e]
grid on; %[output:07eb253e]

